import { InstrumentationConfig, InstrumentationBase, InstrumentationModuleDefinition } from '@opentelemetry/instrumentation';
import * as qdrant from '@qdrant/js-client-rest';

interface QdrantInstrumentationConfig extends InstrumentationConfig {
    /**
     * Whether to log prompts, completions and embeddings on traces.
     * @default true
     */
    traceContent?: boolean;
    /**
     * A custom logger to log any exceptions that happen during span creation.
     */
    exceptionLogger?: (e: Error) => void;
}

declare class QdrantInstrumentation extends InstrumentationBase<any> {
    protected _config: QdrantInstrumentationConfig;
    constructor(config?: QdrantInstrumentationConfig);
    setConfig(config?: QdrantInstrumentationConfig): void;
    protected init(): InstrumentationModuleDefinition;
    manuallyInstrument(module: typeof qdrant): void;
    private wrap;
    private unwrap;
    private wrapperMethod;
    private _startSpan;
    private _endSpan;
    private _setUpsertAttributes;
    private _setDeleteAttributes;
    private _setRetrieveAttributes;
    private _setSearchAttributes;
    private _setSearchResultAttributes;
}

export { QdrantInstrumentation, type QdrantInstrumentationConfig };
